import { describe, expect, it, vi } from 'vitest';
import type * as vscode from 'vscode';
import type { IPhysicsSettings } from '../../../../../src/shared/settings/physics';
import { readGraphViewPhysicsSettings } from '../../../../../src/extension/graphView/settings/physics/reader';

const defaults: IPhysicsSettings = {
  repelForce: 10,
  linkDistance: 80,
  linkForce: 0.15,
  damping: 0.7,
  centerForce: 0.1,
};

describe('graphView/settings/physics/reader', () => {
  it('reads each physics setting from configuration using the configured keys', () => {
    const get = vi.fn((_: string, fallback: number) => fallback + 1);
    const config = { get } as unknown as vscode.WorkspaceConfiguration;

    expect(readGraphViewPhysicsSettings(config, defaults)).toEqual({
      repelForce: 11,
      linkDistance: 81,
      linkForce: 1.15,
      damping: 1.7,
      centerForce: 1.1,
    });
    expect(get.mock.calls.map(([key]) => key)).toEqual([
      'physics.repelForce',
      'physics.linkDistance',
      'physics.linkForce',
      'physics.damping',
      'physics.centerForce',
    ]);
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  resetGraphViewPhysicsSettings,
  updateGraphViewPhysicsSetting,
} from '../../../../../src/extension/graphView/settings/physics/updates';

describe('graph view physics update helpers', () => {
  it('updates a single physics setting in repo-local settings', async () => {
    const update = vi.fn(() => Promise.resolve());

    await updateGraphViewPhysicsSetting('repelForce', 25, {
      getConfiguration: () => ({ update }),
    });

    expect(update).toHaveBeenCalledWith('physics.repelForce', 25);
  });

  it('updates a single physics setting at the requested configuration target', async () => {
    const update = vi.fn(() => Promise.resolve());

    await updateGraphViewPhysicsSetting('damping', 0.35, {
      getConfiguration: () => ({ update }),
      getConfigTarget: () => 'workspace-folder-target',
    });

    expect(update).toHaveBeenCalledWith('physics.damping', 0.35, 'workspace-folder-target');
  });

  it('resets every persisted physics setting back to the config default', async () => {
    const update = vi.fn(() => Promise.resolve());

    await resetGraphViewPhysicsSettings({
      getConfiguration: () => ({ update }),
    });

    expect(update.mock.calls).toEqual([
      ['physics.repelForce', undefined],
      ['physics.linkDistance', undefined],
      ['physics.linkForce', undefined],
      ['physics.damping', undefined],
      ['physics.centerForce', undefined],
    ]);
  });

  it('resets every persisted physics setting at the requested configuration target', async () => {
    const update = vi.fn(() => Promise.resolve());

    await resetGraphViewPhysicsSettings({
      getConfiguration: () => ({ update }),
      getConfigTarget: () => 'workspace-folder-target',
    });

    expect(update.mock.calls).toEqual([
      ['physics.repelForce', undefined, 'workspace-folder-target'],
      ['physics.linkDistance', undefined, 'workspace-folder-target'],
      ['physics.linkForce', undefined, 'workspace-folder-target'],
      ['physics.damping', undefined, 'workspace-folder-target'],
      ['physics.centerForce', undefined, 'workspace-folder-target'],
    ]);
  });
});

import { describe, expect, it } from 'vitest';
import * as vscode from 'vscode';
import { DEFAULT_DIRECTION_COLOR, DEFAULT_FOLDER_NODE_COLOR } from '../../../../src/shared/fileColors';
import {
  areGraphViewSetsEqual,
  getGraphViewConfigTarget,
  normalizeDirectionColor,
  normalizeFolderNodeColor,
  readGraphViewSettings,
  resolveGraphViewDisabledState,
} from '../../../../src/extension/graphView/settings/reader';

describe('graphView/settings/reader', () => {
  it('normalizes invalid direction colors to the default', () => {
    expect(normalizeDirectionColor('not-a-color')).toBe(DEFAULT_DIRECTION_COLOR);
  });

  it('normalizes invalid folder colors to the default', () => {
    expect(normalizeFolderNodeColor('bad-folder-color')).toBe(DEFAULT_FOLDER_NODE_COLOR);
  });

  it('returns workspace config target when workspace folders exist', () => {
    expect(getGraphViewConfigTarget([{ uri: vscode.Uri.file('/workspace') }])).toBe(
      vscode.ConfigurationTarget.Workspace
    );
  });

  it('returns global config target when no workspace folders exist', () => {
    expect(getGraphViewConfigTarget(undefined)).toBe(vscode.ConfigurationTarget.Global);
  });

  it('treats sets with the same members as equal', () => {
    expect(areGraphViewSetsEqual(new Set(['a', 'b']), new Set(['b', 'a']))).toBe(true);
  });

  it('treats sets with different sizes as unequal', () => {
    expect(areGraphViewSetsEqual(new Set(['a']), new Set(['a', 'b']))).toBe(false);
  });

  it('treats sets with missing members as unequal', () => {
    expect(areGraphViewSetsEqual(new Set(['a', 'b']), new Set(['a', 'c']))).toBe(false);
  });

  it('prefers configured disabled state over stored fallback state', () => {
    const result = resolveGraphViewDisabledState(
      new Set(['old-plugin']),
      ['configured-plugin'],
      ['stored-plugin']
    );

    expect([...result.disabledPlugins]).toEqual(['configured-plugin']);
    expect(result.changed).toBe(true);
  });

  it('falls back to stored disabled state when config values are absent', () => {
    const result = resolveGraphViewDisabledState(
      new Set(['stored-plugin']),
      undefined,
      ['stored-plugin']
    );

    expect([...result.disabledPlugins]).toEqual(['stored-plugin']);
    expect(result.changed).toBe(false);
  });

  it('reads graph view settings with normalized defaults', () => {
    const config = {
      get<T>(_section: string, defaultValue: T): T {
        return defaultValue;
      },
    };

    expect(readGraphViewSettings(config)).toEqual({
      bidirectionalEdges: 'separate',
      showOrphans: true,
      directionMode: 'arrows',
      particleSpeed: 0.005,
      particleSize: 4,
      directionColor: DEFAULT_DIRECTION_COLOR,
      showLabels: true,
    });
  });

  it('reads configured graph view settings and preserves valid colors', () => {
    const values = new Map<string, unknown>([
      ['bidirectionalEdges', 'combined'],
      ['showOrphans', false],
      ['directionMode', 'particles'],
      ['particleSpeed', 0.02],
      ['particleSize', 7],
      ['directionColor', '#00ff00'],
      ['showLabels', false],
    ]);
    const config = {
      get<T>(section: string, defaultValue: T): T {
        return (values.get(section) as T | undefined) ?? defaultValue;
      },
    };

    expect(readGraphViewSettings(config)).toEqual({
      bidirectionalEdges: 'combined',
      showOrphans: false,
      directionMode: 'particles',
      particleSpeed: 0.02,
      particleSize: 7,
      directionColor: '#00FF00',
      showLabels: false,
    });
  });
});

import { describe, expect, it, vi } from 'vitest';
import type { ISettingsSnapshot } from '../../../../src/shared/settings/snapshot';
import {
  applyGraphViewAllSettingsSnapshot,
  type GraphViewAllSettingsSyncState,
} from '../../../../src/extension/graphView/settings/sync';

function createSnapshot(
  overrides: Partial<ISettingsSnapshot> = {},
): ISettingsSnapshot {
  return {
    physics: {
      repelForce: 10,
      linkDistance: 80,
      linkForce: 0.15,
      damping: 0.7,
      centerForce: 0.1,
    },
    legends: [{ id: 'group', pattern: 'src/**', color: '#112233' }],
    filterPatterns: ['dist/**'],
    showOrphans: false,
    bidirectionalMode: 'combined',
    directionMode: 'arrows',
    directionColor: '#475569',
    nodeColors: { file: '#999999', folder: '#888888' },
    nodeVisibility: { file: true, folder: true },
    edgeVisibility: { imports: true, nests: false },
    edgeColors: { imports: '#777777', nests: '#666666' },
    pluginOrder: ['codegraphy.markdown', 'codegraphy.python'],
    disabledPlugins: ['codegraphy.python'],
    particleSpeed: 0.005,
    particleSize: 4,
    showLabels: true,
    nodeSizeMode: 'uniform',
    maxFiles: 500,
    ...overrides,
  };
}

function createState(
  overrides: Partial<GraphViewAllSettingsSyncState> = {},
): GraphViewAllSettingsSyncState {
  return {
    viewContext: {},
    userGroups: [],
    filterPatterns: [],
    ...overrides,
  };
}

describe('graphView/settings/sync', () => {
  it('applies the snapshot, recomputes groups, and sends pre/post group messages in order', () => {
    const sendMessage = vi.fn();
    const recomputeGroups = vi.fn();
    const sendGroupsUpdated = vi.fn();
    const state = createState();
    const snapshot = createSnapshot();

    applyGraphViewAllSettingsSnapshot(snapshot, ['venv/**'], state, {
      sendMessage,
      recomputeGroups,
      sendGroupsUpdated,
    });

    expect(state.userGroups).toEqual(snapshot.legends);
    expect(state.filterPatterns).toEqual(['dist/**']);
    expect(recomputeGroups).toHaveBeenCalledOnce();
    expect(sendGroupsUpdated).toHaveBeenCalledOnce();
    expect(sendMessage).toHaveBeenCalled();
  });

  it('sends every pre-group settings message before recomputing groups', () => {
    const order: string[] = [];
    const state = createState();
    const snapshot = createSnapshot();

    applyGraphViewAllSettingsSnapshot(snapshot, ['venv/**'], state, {
      sendMessage: message => {
        order.push(message.type);
      },
      recomputeGroups: () => {
        order.push('RECOMPUTE_GROUPS');
      },
      sendGroupsUpdated: () => {
        order.push('SEND_LEGENDS_UPDATED');
      },
    });

    expect(order.slice(0, 7)).toEqual([
      'PHYSICS_SETTINGS_UPDATED',
      'SETTINGS_UPDATED',
      'DIRECTION_SETTINGS_UPDATED',
      'SHOW_LABELS_UPDATED',
      'RECOMPUTE_GROUPS',
      'SEND_LEGENDS_UPDATED',
      'FILTER_PATTERNS_UPDATED',
    ]);
  });

  it('sends every post-group settings message after groups are recomputed', () => {
    const order: string[] = [];
    const state = createState();
    const snapshot = createSnapshot();

    applyGraphViewAllSettingsSnapshot(snapshot, ['venv/**'], state, {
      sendMessage: message => {
        order.push(message.type);
      },
      recomputeGroups: () => {
        order.push('RECOMPUTE_GROUPS');
      },
      sendGroupsUpdated: () => {
        order.push('SEND_LEGENDS_UPDATED');
      },
    });

    expect(order.slice(-3)).toEqual([
      'FILTER_PATTERNS_UPDATED',
      'MAX_FILES_UPDATED',
      'NODE_SIZE_MODE_UPDATED',
    ]);
  });
});

